    ["Hide on Essential Cooldowns"] = "Скрыть на Essential Cooldowns",
    ["Hide on Right-Click"] = "Скрыть по правому клику",
    ["Hide on Utility Cooldowns"] = "Скрыть на Utility Cooldowns",
    ["Hide the + / - zoom buttons on the minimap. You can still mouse-wheel to zoom."] = "Скрыть кнопки зума + / - на миникарте. По-прежнему можно использовать колесо мыши для зума.",
    ["Hide the 1px accent border drawn around globally skinned frames."] = "Скрыть 1px акцентную рамку, рисуемую вокруг глобально оформленных фреймов.",
